// src/components/Home.js
import React from 'react';
import "../styles/Home.css";

const Home = () => {
  return (
    <section className="hero">
      <div className="overlay"></div>
      <div className="hero-content">
        <p className="tagline">Struggling with Your School or College Project?</p>
        <h1>
          <span>Your Project,</span>{" "}
          <span className="highlight">Our Responsibility.</span>
        </h1>
        <p className="description">
          Welcome to <strong>ProjectDuniya</strong> — your one-stop destination for academic project solutions.
          Whether it's a school model, a science exhibition, or your final year engineering or BCA project — we handle it all with precision.
          <br /><br />
          Our team delivers <strong>customized, affordable, and deadline-driven</strong> solutions with complete guidance and full support.
          Trusted by hundreds of students across India — because your success is our mission.
        </p>
        <div className="hero-buttons">
          <a href="#" className="btn primary">Explore Our Services</a>
          <a href="#" className="btn secondary">Talk to an Expert</a>
        </div>
      </div>
    </section>
  );
};

export default Home;
